/**
 * ============================================================
 * ABNAN CRM — Frontend API Service v2
 * Features:
 *  - Request deduplication (avoid double-fetching same GET)
 *  - Retry on network failure (3x, exponential backoff)
 *  - AbortController support
 *  - Optimistic UI helpers
 *  - Structured error handling
 * ============================================================
 */

import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// ── Axios Instances ───────────────────────────────────────────
export const api = axios.create({
  baseURL: API_URL,
  withCredentials: true,
  timeout: 30000,
  headers: { 'Content-Type': 'application/json' },
});

export const publicApi = axios.create({
  baseURL: API_URL,
  withCredentials: true,
  timeout: 30000,
});

// ── Request Deduplication ─────────────────────────────────────
// Prevents multiple identical GET requests firing simultaneously
const pendingRequests = new Map();

function dedupeKey(config) {
  if (config.method?.toLowerCase() !== 'get') return null;
  return `${config.method}:${config.url}:${JSON.stringify(config.params || {})}`;
}

api.interceptors.request.use((config) => {
  // Attach auth token
  const token = localStorage.getItem('abnan_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;

  // Deduplication for GET requests
  const key = dedupeKey(config);
  if (key) {
    if (pendingRequests.has(key)) {
      // Cancel duplicate request — the first one wins
      const controller = new AbortController();
      controller.abort();
      config.signal = controller.signal;
    } else {
      const controller = new AbortController();
      config.signal = controller.signal;
      config._dedupeKey = key;
      pendingRequests.set(key, controller);
    }
  }

  return config;
});

api.interceptors.response.use(
  (res) => {
    // Clean up dedup map
    const key = res.config._dedupeKey;
    if (key) pendingRequests.delete(key);
    return res;
  },
  (err) => {
    // Clean up dedup map on error too
    const key = err.config?._dedupeKey;
    if (key) pendingRequests.delete(key);

    // Handle 401 — redirect to login
    if (err.response?.status === 401) {
      localStorage.removeItem('abnan_token');
      localStorage.removeItem('abnan_user');
      // Use replace to avoid back-button loop
      window.location.replace('/login');
    }

    // Normalize error message for UI consumption
    const message =
      err.response?.data?.message ||
      (err.code === 'ECONNABORTED' ? 'Request timeout. Coba lagi.' :
       err.code === 'ERR_NETWORK'  ? 'Tidak dapat terhubung ke server.' :
       err.message || 'Terjadi kesalahan jaringan');

    err.userMessage = message;
    return Promise.reject(err);
  }
);

// ── Retry Helper ──────────────────────────────────────────────
// Retry a GET request with exponential backoff on network errors

async function withRetry(fn, retries = 2, delay = 500) {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      return await fn();
    } catch (err) {
      const isNetworkErr = !err.response && err.code !== 'ERR_CANCELED';
      if (attempt < retries && isNetworkErr) {
        await new Promise(r => setTimeout(r, delay * Math.pow(2, attempt)));
      } else {
        throw err;
      }
    }
  }
}

// ── API Modules ───────────────────────────────────────────────

export const authAPI = {
  login:          (data)   => api.post('/auth/login', data),
  me:             ()       => api.get('/auth/me'),
  changePassword: (data)   => api.post('/auth/change-password', data),
};

export const customerPortalAPI = {
  getOverview: () => api.get('/customer-portal/overview'),
};

export const customerSetupAPI = {
  getSetupInfo:    (token)       => publicApi.get(`/customer-portal/setup/${token}`),
  completeSetup:   (token, data) => publicApi.post(`/customer-portal/setup/${token}`, data),
};

export const portalAccessAPI = {
  getByCustomerId: (cid)        => api.get(`/customer-portal-admin/customers/${cid}/access`),
  upsert:          (cid, data)  => api.put(`/customer-portal-admin/customers/${cid}/access`, data),
  createSetupLink: (cid, data)  => api.post(`/customer-portal-admin/customers/${cid}/setup-link`, data),
};

